// Processar resposta da API e extrair informações das edições
const items = [];
const today = new Date();
const todayStr = today.toISOString().split('T')[0]; // YYYY-MM-DD

// Processar resposta da API /published
for (const item of $input.all()) {
  const data = item.json;

  if (data.status === 'success' && data.editions) {
    for (const edition of data.editions) {
      const publicationDate = new Date(edition.publication_date);
      const dateStr = publicationDate.toISOString().split('T')[0];

      // Filtrar edições dos últimos 7 dias
      const daysDiff = (today - publicationDate) / (1000 * 60 * 60 * 24);

      if (daysDiff <= 7) {
        // Determinar se é suplemento
        const supplement = edition.suplement ? '_suplemento' : '';

        items.push({
          json: {
            editionId: edition.id,
            number: edition.number,
            date: dateStr,
            publicationDate: edition.publication_date,
            isSuplement: edition.suplement,
            typeName: edition.edition_type_name,
            downloads: edition.downloads,
            views: edition.views,
            downloadUrl: `https://diario.imprensaoficial.al.gov.br/apinova/api/editions/downloadPdf/${edition.id}`,
            fileName: `diario_oficial_al_${dateStr}_n${edition.number}${supplement}_id${edition.id}.pdf`
          }
        });
      }
    }
  }
}

// Se não encontrou edições, tentar apenas a mais recente
if (items.length === 0) {
  console.log('Nenhuma edição encontrada nos últimos 7 dias, tentando fallback...');

  // Fallback: usar ID estimado baseado na data atual
  const startDate = new Date('2020-01-01');
  const daysSinceStart = Math.floor((today - startDate) / (1000 * 60 * 60 * 24));
  const estimatedId = 45000 + daysSinceStart;

  items.push({
    json: {
      editionId: estimatedId,
      number: 'unknown',
      date: todayStr,
      publicationDate: today.toISOString(),
      isSuplement: false,
      typeName: 'Diário Oficial do Estado de Alagoas',
      downloads: 0,
      views: 0,
      downloadUrl: `https://diario.imprensaoficial.al.gov.br/apinova/api/editions/downloadPdf/${estimatedId}`,
      fileName: `diario_oficial_al_${todayStr}_id${estimatedId}.pdf`
    }
  });
}

console.log(`✅ Encontradas ${items.length} edições para download:`);
items.forEach(item => {
  const edition = item.json;
  console.log(`📄 ${edition.fileName} (${edition.downloads} downloads, ${edition.views} views)`);
});

return items;
